<script setup lang="ts">
import { ref, computed } from 'vue'
import { useRouter } from 'vue-router'
import { useToast } from 'vuestic-ui'
import {
    ServiceType,
    ServiceTypeLabel,
    DiscountType,
    CommissionType,
    CreateCouponRequest,
    CreateServiceDetailInput,
} from './types'
import { useCoupons, PromoterOption } from './composables/useCoupons'

const router = useRouter()
const { init: notify } = useToast()
const { promoters, add } = useCoupons()

// --- 基本資訊 ---
const selectedPromoterId = ref<number | ''>('')
const couponCode = ref('')
// --- 訂單類型設定 ---
const allServiceTypes = Object.values(ServiceType) as ServiceType[]
const selectedServiceTypes = ref<ServiceType[]>([])

type ServiceDetailForm = {
    serviceType: ServiceType
    discountType: DiscountType
    discountValue: number | undefined
    commissionType: CommissionType
    commissionValue: number | undefined
}

const serviceDetailForms = ref<ServiceDetailForm[]>([])

const serviceTypeOptions = computed(() =>
    allServiceTypes.map((st) => ({
        value: st,
        text: ServiceTypeLabel[st],
    })),
)

const addServiceType = (types: ServiceType[]) => {
    // add new entries
    for (const st of types) {
        if (!serviceDetailForms.value.find((f) => f.serviceType === st)) {
            serviceDetailForms.value.push({
                serviceType: st,
                discountType: DiscountType.Fixed,
                discountValue: undefined,
                commissionType: CommissionType.Fixed,
                commissionValue: undefined,
            })
        }
    }
    // remove deselected
    serviceDetailForms.value = serviceDetailForms.value.filter((f) => types.includes(f.serviceType))
}

const onServiceTypesChange = (types: ServiceType[]) => {
    addServiceType(types)
}

// --- 有效期限 ---
const startDate = ref<Date | null>(null)
const endDate = ref<Date | null>(null)
const noEndDate = ref(false)

// --- 推廣夥伴下拉 ---
const promoterOptions = computed(() =>
    promoters.value
        .filter((p) => p.status === 'active')
        .map((p: PromoterOption) => ({
            value: p.id,
            text: p.userName || `Promoter #${p.id}`,
        })),
)

// --- Submit ---
const isSubmitting = ref(false)

const canSubmit = computed(() => {
    if (!selectedPromoterId.value) return false
    if (!couponCode.value || couponCode.value.length < 4 || couponCode.value.length > 20) return false
    if (!/^[a-zA-Z0-9]+$/.test(couponCode.value)) return false
    if (!startDate.value) return false
    if (!noEndDate.value && !endDate.value) return false
    if (serviceDetailForms.value.length === 0) return false
    for (const sd of serviceDetailForms.value) {
        if (sd.discountValue === undefined || sd.commissionValue === undefined) return false
    }
    return true
})

const onSubmit = async () => {
    if (!canSubmit.value) return
    isSubmitting.value = true

    try {
        const serviceDetails: CreateServiceDetailInput[] = serviceDetailForms.value.map((f) => ({
            serviceType: f.serviceType,
            discountType: f.discountType,
            discountValue: f.discountValue!,
            commissionType: f.commissionType,
            commissionValue: f.commissionValue!,
        }))

        const request: CreateCouponRequest = {
            promoterId: selectedPromoterId.value as number,
            code: couponCode.value,
            startTimestamp: String(startDate.value!.getTime()),
            endTimestamp: noEndDate.value ? '0' : String(endDate.value!.getTime()),
            serviceDetails,
        }

        await add(request)
        notify({ message: '優惠碼已建立', color: 'success' })
        router.push({ name: 'coupons' })
    } catch (error) {
        notify({ message: '建立優惠碼失敗，請再試一次', color: 'danger' })
    } finally {
        isSubmitting.value = false
    }
}

const onCancel = () => {
    router.push({ name: 'coupons' })
}
</script>

<template>
    <h1 class="page-title">新增優惠碼</h1>

    <VaForm ref="formRef" @submit.prevent="onSubmit">
        <!-- 基本資訊 -->
        <VaCard class="mb-4">
            <VaCardTitle>基本資訊</VaCardTitle>
            <VaCardContent>
                <div class="grid md:grid-cols-2 gap-4">
                    <VaSelect
                        v-model="selectedPromoterId"
                        label="推廣夥伴"
                        :options="promoterOptions"
                        value-by="value"
                        text-by="text"
                        placeholder="請選擇推廣夥伴"
                        :rules="[(v: any) => !!v || '請選擇推廣夥伴']"
                        searchable
                    />
                    <VaInput
                        v-model="couponCode"
                        label="優惠碼"
                        placeholder="請輸入 4-20 位英數字"
                        :rules="[
                            (v: string) => !!v || '請輸入優惠碼',
                            (v: string) => (v.length >= 4 && v.length <= 20) || '長度需 4-20 字元',
                            (v: string) => /^[a-zA-Z0-9]+$/.test(v) || '僅允許英文與數字',
                        ]"
                    />
                </div>
            </VaCardContent>
        </VaCard>

        <!-- 訂單類型設定 -->
        <VaCard class="mb-4">
            <VaCardTitle>訂單類型設定</VaCardTitle>
            <VaCardContent>
                <VaSelect
                    v-model="selectedServiceTypes"
                    label="訂單類型"
                    :options="serviceTypeOptions"
                    value-by="value"
                    text-by="text"
                    multiple
                    placeholder="請選擇訂單類型"
                    :rules="[(v: any) => (Array.isArray(v) && v.length > 0) || '請選擇至少一個訂單類型']"
                    @update:modelValue="onServiceTypesChange"
                />

                <div class="mt-4 flex flex-col gap-4">
                    <VaCard v-for="form in serviceDetailForms" :key="form.serviceType" outlined>
                        <VaCardTitle>{{ ServiceTypeLabel[form.serviceType] }}</VaCardTitle>
                        <VaCardContent>
                            <div class="grid md:grid-cols-2 gap-4">
                                <!-- 折扣設定 -->
                                <div>
                                    <div class="text-sm font-semibold mb-2">折扣設定</div>
                                    <VaButtonToggle
                                        v-model="form.discountType"
                                        size="small"
                                        color="background-element"
                                        border-color="background-element"
                                        :options="[
                                            { label: '固定金額', value: 'fixed' },
                                            { label: '百分比', value: 'percentage' },
                                        ]"
                                        class="mb-2"
                                    />
                                    <VaInput
                                        v-model.number="form.discountValue"
                                        :label="
                                            form.discountType === 'percentage' ? '折扣百分比 (%)' : '折扣金額 (NT$)'
                                        "
                                        type="number"
                                        :rules="[(v: any) => (v !== null && v !== '') || '請輸入折扣數值']"
                                    />
                                </div>

                                <!-- 佣金設定 -->
                                <div>
                                    <div class="text-sm font-semibold mb-2">佣金設定</div>
                                    <VaButtonToggle
                                        v-model="form.commissionType"
                                        size="small"
                                        color="background-element"
                                        border-color="background-element"
                                        :options="[
                                            { label: '固定金額', value: 'fixed' },
                                            { label: '百分比', value: 'percentage' },
                                        ]"
                                        class="mb-2"
                                    />
                                    <VaInput
                                        v-model.number="form.commissionValue"
                                        :label="
                                            form.commissionType === 'percentage' ? '佣金百分比 (%)' : '佣金金額 (NT$)'
                                        "
                                        type="number"
                                        :rules="[(v: any) => (v !== null && v !== '') || '請輸入佣金數值']"
                                    />
                                </div>
                            </div>
                        </VaCardContent>
                    </VaCard>
                </div>
            </VaCardContent>
        </VaCard>

        <!-- 有效期限 -->
        <VaCard class="mb-4">
            <VaCardTitle>有效期限</VaCardTitle>
            <VaCardContent>
                <div class="grid md:grid-cols-2 gap-4">
                    <VaDateInput v-model="startDate" label="開始日期" :rules="[(v: any) => !!v || '請選擇開始日期']" />
                    <div>
                        <VaDateInput
                            v-model="endDate"
                            label="結束日期"
                            :disabled="noEndDate"
                            :rules="[(v: any) => noEndDate || !!v || '請選擇結束日期']"
                        />
                        <VaCheckbox v-model="noEndDate" label="無結束日期" class="mt-2" />
                    </div>
                </div>
            </VaCardContent>
        </VaCard>

        <!-- 操作按鈕 -->
        <div class="flex justify-end gap-2">
            <VaButton preset="secondary" @click="onCancel">取消</VaButton>
            <VaButton :disabled="!canSubmit" :loading="isSubmitting" @click="onSubmit">建立優惠碼</VaButton>
        </div>
    </VaForm>
</template>
